/**
 * @param {number} n
 * @param {number} pos
 * @param {number} k
 * @return {number}
 */
function solve(n, pos, k) {
    const MOD = 1000000007n;

    // --- Modular Arithmetic Helpers using BigInt ---

    /** Calculates (base^exponent) % MOD */
    const power = (base, exponent) => {
        let res = 1n;
        base %= MOD;
        while (exponent > 0n) {
            if (exponent % 2n === 1n) {
                res = (res * base) % MOD;
            }
            base = (base * base) % MOD;
            exponent /= 2n;
        }
        return res;
    };

    /** Calculates modular inverse using Fermat's Little Theorem */
    const modInverse = (n) => {
        return power(n, MOD - 2n);
    };

    // --- Precalculation ---
    const MAX_N = n;
    const fact = new Array(MAX_N + 1);
    const invFact = new Array(MAX_N + 1);
    fact[0] = 1n;
    for (let i = 1; i <= MAX_N; i++) {
        fact[i] = (fact[i - 1] * BigInt(i)) % MOD;
    }

    invFact[MAX_N] = modInverse(fact[MAX_N]);
    for (let i = MAX_N - 1; i >= 0; i--) {
        invFact[i] = (invFact[i + 1] * BigInt(i + 1)) % MOD;
    }

    /** Calculates nCk % MOD */
    const combinations = (N, K) => {
        if (K < 0 || K > N) return 0n;
        if (K === 0 || K === N) return 1n;
        if (K > N / 2) K = N - K;

        let res = fact[N];
        res = (res * invFact[K]) % MOD;
        res = (res * invFact[N - K]) % MOD;
        return res;
    };

    // --- Problem Specific Calculation ---

    // L: number of people to the left (0 to pos-1)
    const L = pos; 
    // R: number of people to the right (pos+1 to n-1)
    const R = n - 1 - pos; 

    let sum_others = 0n;

    // We need k_L + k_R = k.
    // k_L must satisfy:
    // 1. 0 <= k_L <= L
    // 2. 0 <= k - k_L <= R  =>  k - R <= k_L <= k

    // Determine iteration limits for k_L
    const k_L_min = Math.max(0, k - R);
    const k_L_max = Math.min(L, k);

    for (let k_L = k_L_min; k_L <= k_L_max; k_L++) {
        const k_R = k - k_L;

        // Ways to choose k_L visible from L left people: C(L, k_L)
        const ways_L = combinations(L, k_L);

        // Ways to choose k_R visible from R right people: C(R, k_R)
        const ways_R = combinations(R, k_R);

        // Add product to sum
        const term = (ways_L * ways_R) % MOD;
        sum_others = (sum_others + term) % MOD;
    }

    // The person at pos can choose 'L' or 'R' (2 possibilities), which doesn't affect the count K.
    // Total answer = 2 * S_others
    let final_result = (2n * sum_others) % MOD;

    // Return as standard JS number since the result fits within 10^9 + 7
    return Number(final_result);
}

